from __future__ import annotations

import hashlib
import json
from pathlib import Path
from typing import Any

from common.events import ArtifactRef


def file_sha256(path: Path) -> str:
    hasher = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            hasher.update(chunk)
    return hasher.hexdigest()


def write_json(path: Path, data: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")


def to_artifact_ref(path: Path, artifact_type: str) -> ArtifactRef:
    return ArtifactRef(
        artifact_type=artifact_type,
        uri=str(path),
        sha256=file_sha256(path) if path.exists() and path.is_file() else None,
        size=path.stat().st_size if path.exists() and path.is_file() else None,
    )

from __future__ import annotations

import re
import tomllib
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any

import yaml


@dataclass
class RunSpec:
    setup_commands: list[str] = field(default_factory=list)
    entry_command: str | None = None
    task_inputs: list[dict[str, Any]] = field(default_factory=list)
    env_allowlist: list[str] = field(default_factory=list)
    repeats: int = 10
    timeout_sec: int = 1800

    def to_dict(self) -> dict[str, Any]:
        return {
            "setup_commands": self.setup_commands,
            "entry_command": self.entry_command,
            "task_inputs": self.task_inputs,
            "env_allowlist": self.env_allowlist,
            "repeats": self.repeats,
            "timeout_sec": self.timeout_sec,
        }


def _load_declared_spec(repo_path: Path) -> RunSpec | None:
    spec_path = repo_path / ".agent-complexity.yml"
    if not spec_path.exists():
        return None
    data = yaml.safe_load(spec_path.read_text(encoding="utf-8")) or {}
    return RunSpec(
        setup_commands=list(data.get("setup_commands", [])),
        entry_command=data.get("entry_command"),
        task_inputs=list(data.get("task_inputs", [])),
        env_allowlist=list(data.get("env_allowlist", [])),
        repeats=int(data.get("repeats", 10)),
        timeout_sec=int(data.get("timeout_sec", 1800)),
    )


def _detect_from_templates(repo_path: Path) -> RunSpec | None:
    for candidate in ("main.py", "app.py", "run.py"):
        if (repo_path / candidate).exists():
            return RunSpec(setup_commands=["pip install -r requirements.txt || true"], entry_command=f"python {candidate}")
    if (repo_path / "requirements.txt").exists() and (repo_path / "agent.py").exists():
        return RunSpec(setup_commands=["pip install -r requirements.txt || true"], entry_command="python agent.py")
    if (repo_path / "package.json").exists():
        return RunSpec(setup_commands=["npm install"], entry_command="npm run start")
    return None


def _detect_from_pyproject(repo_path: Path) -> RunSpec | None:
    pyproject = repo_path / "pyproject.toml"
    if not pyproject.exists():
        return None
    data = tomllib.loads(pyproject.read_text(encoding="utf-8"))
    scripts = data.get("project", {}).get("scripts", {})
    if scripts:
        first_script = next(iter(scripts))
        return RunSpec(entry_command=f"python -m {scripts[first_script]}")
    return None


def _detect_from_readme(repo_path: Path) -> RunSpec | None:
    readme_candidates = [repo_path / "README.md", repo_path / "readme.md"]
    cmd_pattern = re.compile(r"^\s*(python\s+[^\n`]+|uv\s+run\s+[^\n`]+|npm\s+run\s+\w+)", re.MULTILINE)
    for readme in readme_candidates:
        if not readme.exists():
            continue
        content = readme.read_text(encoding="utf-8", errors="ignore")
        m = cmd_pattern.search(content)
        if m:
            return RunSpec(entry_command=m.group(1).strip())
    return None


def detect_run_spec(
    repo_path: Path,
    user_spec: dict[str, Any] | None,
    default_repeats: int,
    default_timeout_sec: int,
) -> RunSpec:
    if user_spec and user_spec.get("entry_command"):
        spec = RunSpec(
            setup_commands=list(user_spec.get("setup_commands", [])),
            entry_command=str(user_spec.get("entry_command")),
            task_inputs=list(user_spec.get("task_inputs", [])),
            env_allowlist=list(user_spec.get("env_allowlist", [])),
            repeats=int(user_spec.get("repeats", default_repeats)),
            timeout_sec=int(user_spec.get("timeout_sec", default_timeout_sec)),
        )
        return spec

    spec = _load_declared_spec(repo_path)
    if spec:
        return spec
    spec = _detect_from_templates(repo_path)
    if spec:
        spec.repeats = default_repeats
        spec.timeout_sec = default_timeout_sec
        return spec
    spec = _detect_from_pyproject(repo_path)
    if spec:
        spec.repeats = default_repeats
        spec.timeout_sec = default_timeout_sec
        return spec
    spec = _detect_from_readme(repo_path)
    if spec:
        spec.repeats = default_repeats
        spec.timeout_sec = default_timeout_sec
        return spec

    fallback = RunSpec(
        setup_commands=["pip install -r requirements.txt || true"],
        entry_command="python -c \"print('No entry command detected by analyzer')\"",
        repeats=default_repeats,
        timeout_sec=default_timeout_sec,
    )
    return fallback

from __future__ import annotations

import logging
import time
from uuid import uuid4

try:
    from redis import Redis  # type: ignore
except Exception:  # pragma: no cover
    Redis = None  # type: ignore

from common.settings import get_settings

logger = logging.getLogger(__name__)
settings = get_settings()


class SecretStore:
    def __init__(self) -> None:
        self._memory: dict[str, tuple[str, float]] = {}
        self.redis = Redis.from_url(settings.redis_url) if Redis is not None else None

    def put_token(self, token: str, ttl_seconds: int = 3600) -> str:
        ref = f"secret:{uuid4()}"
        if self.redis is not None:
            self.redis.set(name=ref, value=token, ex=ttl_seconds)
        else:
            self._memory[ref] = (token, time.time() + ttl_seconds)
        return ref

    def pop_token(self, ref: str | None) -> str | None:
        if not ref:
            return None
        if self.redis is not None:
            with self.redis.pipeline() as pipe:
                pipe.get(ref)
                pipe.delete(ref)
                token, _ = pipe.execute()
            if token is None:
                return None
            if isinstance(token, bytes):
                return token.decode("utf-8")
            return str(token)
        token, expire_at = self._memory.pop(ref, (None, 0))
        if token is None or time.time() > expire_at:
            return None
        return token


def get_secret_store() -> SecretStore:
    return SecretStore()

from __future__ import annotations

from datetime import datetime, timezone
from typing import Iterable

from sqlalchemy import select
from sqlalchemy.orm import Session

from common.events import ArtifactRef, MetricRecord
from services.orchestrator.constants import AnalysisStatus
from services.orchestrator.models import AnalysisArtifact, AnalysisJob, AnalysisMetric
from services.orchestrator.schemas import AnalysisCreateRequest


def utcnow() -> datetime:
    return datetime.now(timezone.utc)


class AnalysisRepository:
    def __init__(self, session: Session):
        self.session = session

    def create_job(self, payload: AnalysisCreateRequest, auth_ref: str | None) -> AnalysisJob:
        run_spec_dict = payload.run_spec.model_dump() if payload.run_spec else {}
        job = AnalysisJob(
            repo_url=str(payload.repo_url),
            git_ref=payload.git_ref,
            auth_ref=auth_ref,
            run_profile=payload.run_profile,
            run_spec=run_spec_dict,
            repeats=payload.repeats,
            timeout_sec=payload.timeout_sec,
            status=AnalysisStatus.QUEUED.value,
        )
        self.session.add(job)
        self.session.flush()
        return job

    def get_job(self, analysis_id: str) -> AnalysisJob | None:
        return self.session.get(AnalysisJob, analysis_id)

    def update_job_status(
        self,
        job: AnalysisJob,
        status: AnalysisStatus,
        error_summary: str | None = None,
        observability_coverage: float | None = None,
    ) -> AnalysisJob:
        job.status = status.value
        if status == AnalysisStatus.RUNNING and not job.started_at:
            job.started_at = utcnow()
        if status in {AnalysisStatus.REPORT_READY, AnalysisStatus.FAILED, AnalysisStatus.PARTIAL}:
            job.finished_at = utcnow()
        if error_summary is not None:
            job.error_summary = error_summary
        if observability_coverage is not None:
            job.observability_coverage = observability_coverage
        self.session.add(job)
        return job

    def replace_metrics(self, analysis_id: str, metrics: Iterable[MetricRecord]) -> None:
        existing = self.session.scalars(
            select(AnalysisMetric).where(AnalysisMetric.analysis_id == analysis_id)
        ).all()
        for row in existing:
            self.session.delete(row)
        for metric in metrics:
            self.session.add(
                AnalysisMetric(
                    analysis_id=analysis_id,
                    metric_code=metric.metric_code,
                    scope=metric.scope,
                    run_id=metric.run_id,
                    raw_value=metric.raw_value,
                    value_json=metric.value_json,
                    agg_type=metric.agg_type,
                    ci_low=metric.ci_low,
                    ci_high=metric.ci_high,
                    evidence_ref=metric.evidence_ref,
                )
            )

    def replace_artifacts(self, analysis_id: str, artifacts: Iterable[ArtifactRef]) -> None:
        existing = self.session.scalars(
            select(AnalysisArtifact).where(AnalysisArtifact.analysis_id == analysis_id)
        ).all()
        for row in existing:
            self.session.delete(row)
        for artifact in artifacts:
            self.session.add(
                AnalysisArtifact(
                    analysis_id=analysis_id,
                    artifact_type=artifact.artifact_type,
                    uri=artifact.uri,
                    sha256=artifact.sha256,
                    size_bytes=artifact.size,
                    metadata_json={},
                )
            )

from __future__ import annotations

from contextlib import contextmanager
from typing import Iterator

from sqlalchemy import create_engine
from sqlalchemy.orm import DeclarativeBase, Session, sessionmaker

from common.settings import get_settings


class Base(DeclarativeBase):
    pass


settings = get_settings()


def _build_engine():
    try:
        return create_engine(settings.database_url, future=True, pool_pre_ping=True)
    except ModuleNotFoundError:
        fallback_url = "sqlite+pysqlite:///./data/agentic.db"
        return create_engine(fallback_url, future=True, pool_pre_ping=True)


engine = _build_engine()
SessionLocal = sessionmaker(bind=engine, autoflush=False, autocommit=False, expire_on_commit=False)


def init_db() -> None:
    from services.orchestrator import models  # noqa: F401

    Base.metadata.create_all(bind=engine)


@contextmanager
def session_scope() -> Iterator[Session]:
    session = SessionLocal()
    try:
        yield session
        session.commit()
    except Exception:
        session.rollback()
        raise
    finally:
        session.close()

