:root {
  --bg: #f3f6fb;
  --surface: #ffffff;
  --line: #d4dde8;
  --text: #162132;
  --muted: #5a6a80;
  --brand: #1458d2;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: "IBM Plex Sans", "Segoe UI", sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at 15% 20%, #d6e4fb 0%, transparent 40%),
    radial-gradient(circle at 85% 15%, #e9f3d9 0%, transparent 35%),
    var(--bg);
}

main {
  max-width: 1000px;
  margin: 32px auto;
  padding: 0 16px 32px;
}

.card {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 12px;
  padding: 20px;
  box-shadow: 0 10px 26px rgba(19, 36, 70, 0.08);
}

label {
  display: block;
  margin-top: 12px;
  margin-bottom: 4px;
  font-weight: 600;
}

input,
textarea,
select,
button {
  width: 100%;
  font-size: 14px;
}

input,
textarea,
select {
  border: 1px solid var(--line);
  border-radius: 8px;
  padding: 10px;
  background: #fff;
}

textarea {
  min-height: 110px;
}

button {
  margin-top: 14px;
  border: none;
  border-radius: 10px;
  padding: 12px 16px;
  background: linear-gradient(135deg, #195fd8, #0a4bb9);
  color: #fff;
  font-weight: 700;
  cursor: pointer;
}

.muted {
  color: var(--muted);
}

.grid {
  display: grid;
  gap: 14px;
}

@media (min-width: 860px) {
  .grid {
    grid-template-columns: 1fr 1fr;
  }
}

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:8000";

export interface AnalysisCreatePayload {
  repo_url: string;
  git_ref: string;
  run_profile: string;
  repeats?: number;
  timeout_sec?: number;
  auth_token?: string;
  run_spec?: {
    setup_commands: string[];
    entry_command?: string;
    task_inputs: Record<string, unknown>[];
    env_allowlist: string[];
    repeats?: number;
    timeout_sec?: number;
  };
}

export async function createAnalysis(payload: AnalysisCreatePayload) {
  const res = await fetch(`${API_BASE}/api/v1/analyses`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload)
  });
  if (!res.ok) {
    throw new Error(`Create failed: ${await res.text()}`);
  }
  return await res.json();
}

export async function getAnalysis(id: string) {
  const res = await fetch(`${API_BASE}/api/v1/analyses/${id}`, { cache: "no-store" });
  if (!res.ok) {
    throw new Error(`Status fetch failed: ${await res.text()}`);
  }
  return await res.json();
}

export async function getReport(id: string) {
  const res = await fetch(`${API_BASE}/api/v1/analyses/${id}/report`, { cache: "no-store" });
  if (!res.ok) {
    throw new Error(`Report fetch failed: ${await res.text()}`);
  }
  return await res.json();
}

export async function getMetrics(id: string) {
  const res = await fetch(`${API_BASE}/api/v1/analyses/${id}/metrics`, { cache: "no-store" });
  if (!res.ok) {
    throw new Error(`Metrics fetch failed: ${await res.text()}`);
  }
  return await res.json();
}

