"use client";

import { useEffect, useMemo, useState } from "react";
import { getAnalysis, getMetrics, getReport } from "../../../lib/api";

const REFRESH_MS = 5000;

export default function AnalysisDetailPage({ params }: { params: { id: string } }) {
  const id = params.id;
  const [statusData, setStatusData] = useState<any>(null);
  const [report, setReport] = useState<any>(null);
  const [metrics, setMetrics] = useState<any[]>([]);
  const [error, setError] = useState("");

  useEffect(() => {
    let mounted = true;
    async function fetchAll() {
      try {
        const [statusRes, reportRes, metricRes] = await Promise.all([
          getAnalysis(id),
          getReport(id),
          getMetrics(id)
        ]);
        if (!mounted) return;
        setStatusData(statusRes);
        setReport(reportRes);
        setMetrics(metricRes);
      } catch (err: any) {
        if (!mounted) return;
        setError(err.message || "load failed");
      }
    }
    fetchAll();
    const timer = setInterval(fetchAll, REFRESH_MS);
    return () => {
      mounted = false;
      clearInterval(timer);
    };
  }, [id]);

  const grouped = useMemo(() => {
    const map: Record<string, any[]> = {};
    for (const item of metrics) {
      const key = item.scope || "unknown";
      if (!map[key]) map[key] = [];
      map[key].push(item);
    }
    return map;
  }, [metrics]);

  return (
    <main>
      <h1>Analysis #{id}</h1>
      {error ? <p style={{ color: "#b40000" }}>{error}</p> : null}
      <section className="card">
        <h3>Status</h3>
        <pre>{JSON.stringify(statusData, null, 2)}</pre>
      </section>
      <section className="card" style={{ marginTop: 16 }}>
        <h3>Report</h3>
        <pre>{JSON.stringify(report, null, 2)}</pre>
      </section>
      <section className="card" style={{ marginTop: 16 }}>
        <h3>Metrics</h3>
        {Object.entries(grouped).map(([scope, rows]) => (
          <div key={scope} style={{ marginBottom: 12 }}>
            <h4>{scope}</h4>
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr>
                  <th align="left">Code</th>
                  <th align="left">Value</th>
                  <th align="left">CI</th>
                </tr>
              </thead>
              <tbody>
                {rows.slice(0, 120).map((row, idx) => (
                  <tr key={`${scope}-${idx}`}>
                    <td>{row.metric_code}</td>
                    <td>{row.raw_value ?? "-"}</td>
                    <td>
                      {row.ci_low !== null && row.ci_high !== null
                        ? `[${row.ci_low}, ${row.ci_high}]`
                        : "-"}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ))}
      </section>
    </main>
  );
}

from agentic_runtime_hooks import ac_track_call
import pickle

import pandas as pd


class ToolRegistry:
    def __init__(self, tools):
        self.tools = []
        self.next_id = 0

        for j in ac_track_call('tool_call', 'tools.values', tools.values):
            for tool in j:
                ac_track_call('tool_call', 'self.register_tool', self.register_tool, tool)

        docs = []
        for tool_id in range(len(self.tools)):
            docs.append([int(tool_id), ac_track_call('tool_call', 'self.get_tool_by_id', self.get_tool_by_id, int(tool_id))])
        self.document_df = pd.DataFrame(docs, columns=["docid", "document_content"])

        # self.langchain_tools = {}
        # for module, api_list in tools.items():
        #    self.langchain_tools.update({self.get_id_by_name(api['name']): api_schema_to_langchain_tool(api, mode = 'custom_tool', module_name = module) for api in api_list})

    def register_tool(self, tool):
        if ac_track_call('tool_call', 'self.validate_tool', self.validate_tool, tool):
            tool["id"] = self.next_id
            ac_track_call('tool_call', 'self.tools.append', self.tools.append, tool)
            self.next_id += 1
        else:
            raise ValueError("Invalid tool format")

    def validate_tool(self, tool):
        required_keys = ["name", "description", "required_parameters"]
        return all(key in tool for key in required_keys)

    def get_tool_by_name(self, name):
        for tool in self.tools:
            if tool["name"] == name:
                return tool
        return None

    def get_tool_by_id(self, tool_id):
        for tool in self.tools:
            if tool["id"] == tool_id:
                return tool
        return None

    def get_id_by_name(self, name):
        for tool in self.tools:
            if tool["name"] == name:
                return tool["id"]
        return None

    def get_name_by_id(self, tool_id):
        for tool in self.tools:
            if tool["id"] == tool_id:
                return tool["name"]
        return None

    def list_tools(self):
        return [{"name": tool["name"], "id": tool["id"]} for tool in self.tools]

    def remove_tool_by_id(self, tool_id):
        # Remove the tool with the given id
        tool = ac_track_call('tool_call', 'self.get_tool_by_id', self.get_tool_by_id, tool_id)
        if tool:
            self.tools = [t for t in self.tools if t["id"] != tool_id]
            return True
        return False

    def remove_tool_by_name(self, name):
        # Remove the tool with the given name
        tool = ac_track_call('tool_call', 'self.get_tool_by_name', self.get_tool_by_name, name)
        if tool:
            self.tools = [t for t in self.tools if t["name"] != name]
            return True
        return False

    def save_registry(self, filename):
        with open(filename, "wb") as file:
            pickle.dump(self, file)

    # def get_langchain_tool_by_id(self, id):
    #     return self.langchain_tools[id]

    @staticmethod
    def load_registry(filename):
        with open(filename, "rb") as file:
            return pickle.load(file)

import numpy as np
import pandas as pd

from biomni.task.base_task import base_task

np.random.seed(42)


def shuffle(x):
    np.random.shuffle(x)
    return x


class lab_bench(base_task):
    def __init__(self, path="./data", dataset="DbQA"):
        if dataset not in ["DbQA", "SeqQA"]:
            raise ValueError("dataset must be one of 'DbQA', 'SeqQA'")

        self.dataset = dataset  # Store dataset type
        df = pd.read_parquet(path + "/" + dataset + "/train-00000-of-00001_test.parquet")

        self.prompt = """The following is a multiple choice question about biology.
Please answer by responding with the letter of the correct answer.

Question: {question}
Options:
{options}

You MUST include the letter of the correct answer within the following tags:
[ANSWER] and [/ANSWER]. For example, '[ANSWER]<answer>[/ANSWER]',
where <answer> is the correct letter. Always answer in exactly this format
of a single letter between the two tags, even if you are unsure.
We require this because we use automatic parsing.
            """

        np.random.seed(42)
        df["options"] = df.apply(
            lambda x: shuffle(
                x.distractors.tolist() + [x.ideal] + ["Insufficient information to answer the question."]
            ),
            axis=1,
        )
        df["options_letters"] = df.options.apply(
            lambda x: "\n".join([chr(ord("A") + i) + "." + item for i, item in enumerate(x)])
        )
        df["letter_answer"] = df.apply(
            lambda x: chr(ord("A") + np.where(np.array(x.options) == x.ideal)[0][0]),
            axis=1,
        )
        df["letter_refrain"] = df.apply(
            lambda x: chr(
                ord("A") + np.where(np.array(x.options) == "Insufficient information to answer the question.")[0][0]
            ),
            axis=1,
        )

        self.query = df.question.values
        self.options = df.options_letters.values
        self.answer = df.letter_answer.values
        self.refrain_label = df.letter_refrain.values

        # Store protocol information if available
        self.protocol = df.protocol.values if "protocol" in df.columns else None

    def get_example(self, index=None):
        if index is None:
            index = np.random.randint(len(self.query))

        if self.dataset == "ProtocolQA" and self.protocol is not None:
            return {
                "prompt": self.prompt.format(
                    protocol=self.protocol[index],
                    question=self.query[index],
                    options=self.options[index],
                ),
                "answer": self.answer[index],
            }
        else:
            return {
                "prompt": self.prompt.format(question=self.query[index], options=self.options[index]),
                "answer": self.answer[index],
            }

    def get_iterator(self):
        for i in range(len(self.query)):
            yield self.get_example(i)

    def evaluate(self, response):
        ## expected a list/array of symbols
        from sklearn.metrics import accuracy_score

        ground_truth = self.answer
        response = np.array(response)

        return {
            "accuracy": accuracy_score(ground_truth, response),
            "coverage": np.mean(response != self.refrain_label),
            "refrain_ratio": np.mean(response == self.refrain_label),
            "precision": accuracy_score(
                ground_truth[np.where(response != self.refrain_label)],
                response[np.where(response != self.refrain_label)],
            ),
        }

    def output_class(self):
        from pydantic import BaseModel, Field

        class MultipleChoiceOutput(BaseModel):
            """Multiple choice output."""

            choice: str | None = Field(
                description="Multiple choice answer. For example, if there is <answer>A</answer> in the prompt, the output should be 'A'."
            )

        return MultipleChoiceOutput

class base_task:
    def __init__(self):
        pass

    def get_example(self):
        pass

    def get_iterator(self):
        pass

    def evaluate(self):
        pass

    def output_class(self):
        pass

    def get_prompt_from_input(self, input):
        return self.get_example(input)["prompt"]

